protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 renamed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator,
        // so we must keep the old name.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer embeds the discriminator in the JSON id property.
        // Existing documents use the compound format "Product|123".
        // Preserve it so FindAsync and point-reads continue to work against existing data.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // Removed HasIndex: EF Core 9 Cosmos provider now throws at startup for HasIndex calls.
    // Cosmos DB indexing is managed via the container's indexing policy (Azure Portal / Bicep / Terraform).
}

